        bodyPlain: 'This week in tech: AI advances, new frameworks, industry insights...',
      });

      const request: BatchClassificationRequest = {
        emails: [
          {
            ...newsletterEmail,
            bodyHtml: '<h1>This week in tech</h1><p>AI advances, new frameworks, industry insights...</p>',
            headers: [
              { name: 'Message-ID', value: '<newsletter-002@techcorp.com>' },
              { name: 'List-Unsubscribe', value: '<mailto:unsubscribe@techcorp.com>' },
            ],
          },
        ],
        sessionId: '456e7890-e89b-12d3-a456-426614174001',
        processingMode: 'sequential',
      };

      // This MUST fail - no implementation exists
      const response = await engine.classifyBatch(request);

      // Newsletter is a subtype under subscriptionContent, not a top-level category
      expect(response.results[0].primaryCategory).toBe('subscriptionContent');
      expect(response.results[0].subtype).toBe('newsletter'); // "newsletter" is a subtype under "subscriptionContent"
      expect(response.performanceMetrics.parallelStagesCount).toBe(0); // Sequential mode
    });

    it('should validate batch size limits', async () => {
      // Use centralized mock to generate batch of test emails
      const emails: EmailContent[] = Array.from({ length: 101 }, (_, i) => ({
        ...createMockEmail({
          id: `test-email-${i}`,
